import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secretFile.txt";
        String baseDirectory = "/path/to/directory/";

        Path basePath = Paths.get(baseDirectory).toAbsolutePath().normalize();
        Path userPath = Paths.get(userInput).normalize();

        if (!userPath.startsWith(basePath)) {
            System.out.println("Invalid file path");
            return;
        }

        Path filePath = basePath.resolve(userPath);

        try {
            byte[] fileContent = Files.readAllBytes(filePath);
            System.out.println(new String(fileContent));
        } catch (Exception e) {
            System.out.println("File not found or error reading file");
        }
    }
}

